}

.insight-card p,
.news-card p {
  margin: 10px 0 0;
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
  color: #4f5677;
}

.news-card p {
  display: block;
  border-bottom: 1px solid #eceffa;
  padding-bottom: 10px;
}

.news-card p:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.news-card span {
  display: block;
  margin-top: 4px;
