  font-size: 0.84rem;
}

.indices-section {
}

.indices-grid {
  margin-top: 12px;
  display: grid;
  gap: 12px;
  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
}

.index-card {
  border: 1px solid #e4e8fa;
