import { useMemo, useState } from "react";
import { Link } from "react-router";
import { Header } from "../../components/Header.tsx";
import { stocks } from "../../data/stocks";
import { useCart } from "../../context/CartContext";
import "./HomePage.css";


export function HomePage() {
  const { addToCart } = useCart();
  const [searchText, setSearchText] = useState("");

  const topGainers = useMemo(() => [...stocks].sort((a, b) => b.changePercent - a.changePercent).slice(0, 4), []);
  const topLosers = useMemo(() => [...stocks].sort((a, b) => a.changePercent - b.changePercent).slice(0, 4), []);
  const mostActive = useMemo(() => [...stocks].sort((a, b) => b.volume - a.volume).slice(0, 5), []);

  const sectorOverview = useMemo(() => {
    const totals = new Map<string, { total: number; count: number }>();

    stocks.forEach((stock) => {
      const current = totals.get(stock.sector) ?? { total: 0, count: 0 };
      totals.set(stock.sector, {
        total: current.total + stock.changePercent,
        count: current.count + 1,
      });
    });

    return Array.from(totals.entries())
      .map(([sector, data]) => ({
        sector,
        avgChange: data.total / data.count,
      }))
      .sort((a, b) => b.avgChange - a.avgChange);
  }, []);

  const strongestSector = sectorOverview[0];
  const weakestSector = sectorOverview[sectorOverview.length - 1];

  const marketAverage = useMemo(() => {
    const total = stocks.reduce((sum, stock) => sum + stock.changePercent, 0);
    return total / stocks.length;
  }, []);

  const indexSnapshot = [
    { name: "S&P 500", value: "5,318.24", change: 0.78 },
    { name: "NASDAQ", value: "16,904.70", change: 1.12 },
    { name: "Dow Jones", value: "39,891.56", change: 0.32 },
    { name: "Russell 2000", value: "2,102.63", change: -0.21 },
  ];

  const stockHeadlines = topGainers.slice(0, 3).map((stock) => ({
    id: `${stock.id}-headline`,
    title: `${stock.symbol} jumps ${stock.changePercent.toFixed(2)}% as momentum accelerates`,
    source: "TradePulseAI News Desk",
  }));

  const newsTickerItems = [
    "Fed signals a data-driven stance ahead of next policy meeting",
    "Tech leads gains as AI infrastructure demand remains strong",
    "Energy stocks rise with crude oil rebounding above weekly lows",
    "Retail earnings surprise to the upside in latest quarter",
  ];

  const upcomingAlerts = [
    { label: "Earnings", company: "NVIDIA (NVDA)", when: "Tomorrow, 8:30 PM" },
    { label: "Earnings", company: "Tesla (TSLA)", when: "Mar 21, 9:00 PM" },
    { label: "Dividend", company: "Johnson & Johnson (JNJ)", when: "Ex-date: Mar 25" },
    { label: "Dividend", company: "Procter & Gamble (PG)", when: "Ex-date: Mar 28" },
  ];

  const filteredStocks = useMemo(() => {
    const query = searchText.trim().toLowerCase();

    if (!query) {
      return stocks;
    }

    return stocks.filter((stock) => {
      const haystack = [stock.symbol, stock.name, stock.sector, stock.exchange, stock.keywords.join(" ")].join(" ").toLowerCase();
      return haystack.includes(query);
    });
  }, [searchText]);

  return (
    <>
      <Header />

      <main className="home-page">
        <section className="home-hero">
          <p className="home-eyebrow">Market pulse in real time</p>
          <h1>Track stocks, read AI signals, and trade with confidence.</h1>
          <p className="home-subtitle">Search your favorite stocks, view recommendations, and unlock deeper analytics after sign in.</p>
              <div className="home-hero-actions">
                <Link to="/login" className="home-btn-primary">Sign in</Link>
                <Link to="/registration" className="home-btn-secondary">Create account</Link>
                <Link to="/watchlist" className="home-btn-secondary"> Watchlist</Link>
                <Link to="/about" className="home-btn-secondary">About us</Link>
              </div>
        </section>

        <div className="home-section-shell">
        <section className="home-stocks-section" aria-labelledby="stocks-heading">
          <div className="stocks-top-row">
            <h2 id="stocks-heading">Explore stocks</h2>
            <p>{filteredStocks.length} result{filteredStocks.length === 1 ? "" : "s"}</p>
          </div>

          <div className="search-wrapper">
            <label htmlFor="stock-search" className="search-label">Search by symbol, company, sector, or keyword</label>
            <input
              id="stock-search"
              type="search"
              className="stock-search-input"
              placeholder="Try: AAPL, technology, banking, ai"
              value={searchText}
              onChange={(event) => setSearchText(event.target.value)}
            />
          </div>

          <div className="stocks-grid">
            {filteredStocks.map((stock) => {
              const isPositive = stock.changePercent >= 0;

              return (
                <article className="stock-card" key={stock.id}>
                  <div className="stock-card-header">
                    <div>
                      <h3>{stock.symbol}</h3>
                      <p>{stock.name}</p>
                    </div>
                    <span className={`recommendation-badge ${stock.recommendation.toLowerCase()}`}>{stock.recommendation}</span>
                  </div>

                  <div className="stock-price-row">
                    <strong>${stock.price.toFixed(2)}</strong>
                    <span className={isPositive ? "price-up" : "price-down"}>{isPositive ? "+" : ""}{stock.changePercent.toFixed(2)}%</span>
                  </div>

                  <div className="stock-meta-grid">
                    <p><span>Sector</span>{stock.sector}</p>
                    <p><span>Exchange</span>{stock.exchange}</p>
                    <p><span>Market Cap</span>${stock.marketCapBillion}B</p>
                    <p><span>Volume</span>{stock.volume.toLocaleString()}</p>
                  </div>

                  <p className="stock-rating">AI confidence {stock.rating.score}/5 ({stock.rating.analysts} analysts)</p>

                  <button 
                    className="stock-add-to-cart-btn"
                    onClick={() => addToCart(stock.id, stock.symbol, stock.price, 1)}
                  >
                     Add to cart
                  </button>
                </article>
              );
            })}
          </div>

          {filteredStocks.length === 0 && (
            <div className="empty-search-state">
              <p>No stocks matched your search.</p>
              <button type="button" className="clear-search-btn" onClick={() => setSearchText("")}>Clear search</button>
            </div>
          )}
        </section>

        <section className="market-news-ticker" aria-label="Market news ticker">
          <div className="ticker-track">
            {[...newsTickerItems, ...newsTickerItems].map((item, index) => (
              <span key={`${item}-${index}`}>• {item}</span>
            ))}
          </div>
        </section>

        <section className="market-insights-grid">
          <article className="insight-card">
            <h3>Top Gainers</h3>
            {topGainers.map((stock) => (
              <p key={`${stock.id}-g`}><strong>{stock.symbol}</strong><span className="price-up">+{stock.changePercent.toFixed(2)}%</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Top Losers</h3>
            {topLosers.map((stock) => (
              <p key={`${stock.id}-l`}><strong>{stock.symbol}</strong><span className="price-down">{stock.changePercent.toFixed(2)}%</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Most Active</h3>
            {mostActive.map((stock) => (
              <p key={`${stock.id}-a`}><strong>{stock.symbol}</strong><span>{stock.volume.toLocaleString()}</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Sector Overview</h3>
            {sectorOverview.map((sector) => (
              <p key={sector.sector}><strong>{sector.sector}</strong><span className={sector.avgChange >= 0 ? "price-up" : "price-down"}>{sector.avgChange >= 0 ? "+" : ""}{sector.avgChange.toFixed(2)}%</span></p>
            ))}
          </article>
        </section>

        <section className="indices-section">
          <h3>Market Indices Snapshot</h3>
          <div className="indices-grid">
            {indexSnapshot.map((index) => (
              <article className="index-card" key={index.name}>
                <p>{index.name}</p>
                <strong>{index.value}</strong>
                <span className={index.change >= 0 ? "price-up" : "price-down"}>{index.change >= 0 ? "+" : ""}{index.change.toFixed(2)}%</span>
              </article>
            ))}
          </div>
        </section>

        <section className="daily-summary-card">
          <h3>Daily Summary</h3>
          <p>
            Today, the market is <strong>{marketAverage >= 0 ? "up" : "down"} {Math.abs(marketAverage).toFixed(2)}%</strong>. Top performing sector: <strong>{strongestSector?.sector}</strong> ({strongestSector?.avgChange.toFixed(2)}%). Weakest sector: <strong>{weakestSector?.sector}</strong> ({weakestSector?.avgChange.toFixed(2)}%).
          </p>
        </section>

        <section className="news-alerts-grid">
          <article className="news-card">
            <h3>Stock-specific headlines</h3>
            {stockHeadlines.map((headline) => (
              <p key={headline.id}><strong>{headline.title}</strong><span>{headline.source}</span></p>
            ))}
          </article>

          <article className="news-card">
            <h3>Earnings / Dividend Alerts</h3>
            {upcomingAlerts.map((alert) => (
              <p key={`${alert.company}-${alert.when}`}><strong>{alert.label}: {alert.company}</strong><span>{alert.when}</span></p>
            ))}
          </article>
        </section>
        </div>
      </main>
    </>
  );
}

import { useMemo, useState } from "react";
import { Link } from "react-router";
import { Header } from "../../components/Header.tsx";
import { stocks } from "../../data/stocks";
import { useCart } from "../../context/CartContext";
import { useWatchlist } from "../../context/WatchlistContext";
import "./HomePage.css";


export function HomePage() {
  const { addToCart } = useCart();
  const { addToWatchlist } = useWatchlist();
  const [searchText, setSearchText] = useState("");

  const topGainers = useMemo(() => [...stocks].sort((a, b) => b.changePercent - a.changePercent).slice(0, 4), []);
  const topLosers = useMemo(() => [...stocks].sort((a, b) => a.changePercent - b.changePercent).slice(0, 4), []);
  const mostActive = useMemo(() => [...stocks].sort((a, b) => b.volume - a.volume).slice(0, 5), []);

  const sectorOverview = useMemo(() => {
    const totals = new Map<string, { total: number; count: number }>();

    stocks.forEach((stock) => {
      const current = totals.get(stock.sector) ?? { total: 0, count: 0 };
      totals.set(stock.sector, {
        total: current.total + stock.changePercent,
        count: current.count + 1,
      });
    });

    return Array.from(totals.entries())
      .map(([sector, data]) => ({
        sector,
        avgChange: data.total / data.count,
      }))
      .sort((a, b) => b.avgChange - a.avgChange);
  }, []);

  const strongestSector = sectorOverview[0];
  const weakestSector = sectorOverview[sectorOverview.length - 1];

  const marketAverage = useMemo(() => {
    const total = stocks.reduce((sum, stock) => sum + stock.changePercent, 0);
    return total / stocks.length;
  }, []);

  const indexSnapshot = [
    { name: "S&P 500", value: "5,318.24", change: 0.78 },
    { name: "NASDAQ", value: "16,904.70", change: 1.12 },
    { name: "Dow Jones", value: "39,891.56", change: 0.32 },
    { name: "Russell 2000", value: "2,102.63", change: -0.21 },
  ];

  const stockHeadlines = topGainers.slice(0, 3).map((stock) => ({
    id: `${stock.id}-headline`,
    title: `${stock.symbol} jumps ${stock.changePercent.toFixed(2)}% as momentum accelerates`,
    source: "TradePulseAI News Desk",
  }));

  const newsTickerItems = [
    "Fed signals a data-driven stance ahead of next policy meeting",
    "Tech leads gains as AI infrastructure demand remains strong",
    "Energy stocks rise with crude oil rebounding above weekly lows",
    "Retail earnings surprise to the upside in latest quarter",
  ];

  const upcomingAlerts = [
    { label: "Earnings", company: "NVIDIA (NVDA)", when: "Tomorrow, 8:30 PM" },
    { label: "Earnings", company: "Tesla (TSLA)", when: "Mar 21, 9:00 PM" },
    { label: "Dividend", company: "Johnson & Johnson (JNJ)", when: "Ex-date: Mar 25" },
    { label: "Dividend", company: "Procter & Gamble (PG)", when: "Ex-date: Mar 28" },
  ];

  const filteredStocks = useMemo(() => {
    const query = searchText.trim().toLowerCase();

    if (!query) {
      return stocks;
    }

    return stocks.filter((stock) => {
      const haystack = [stock.symbol, stock.name, stock.sector, stock.exchange, stock.keywords.join(" ")].join(" ").toLowerCase();
      return haystack.includes(query);
    });
  }, [searchText]);

  return (
    <>
      <Header />

      <main className="home-page">
        <section className="home-hero">
          <p className="home-eyebrow">Market pulse in real time</p>
          <h1>Track stocks, read AI signals, and trade with confidence.</h1>
          <p className="home-subtitle">Search your favorite stocks, view recommendations, and unlock deeper analytics after sign in.</p>
              <div className="home-hero-actions">
                <Link to="/login" className="home-btn-primary">Sign in</Link>
                <Link to="/registration" className="home-btn-secondary">Create account</Link>
                <Link to="/watchlist" className="home-btn-secondary"> Watchlist</Link>
                <Link to="/about" className="home-btn-secondary">About us</Link>
              </div>
        </section>

        <div className="home-section-shell">
        <section className="home-stocks-section" aria-labelledby="stocks-heading">
          <div className="stocks-top-row">
            <h2 id="stocks-heading">Explore stocks</h2>
            <p>{filteredStocks.length} result{filteredStocks.length === 1 ? "" : "s"}</p>
          </div>

          <div className="search-wrapper">
            <label htmlFor="stock-search" className="search-label">Search by symbol, company, sector, or keyword</label>
            <input
              id="stock-search"
              type="search"
              className="stock-search-input"
              placeholder="Try: AAPL, technology, banking, ai"
              value={searchText}
              onChange={(event) => setSearchText(event.target.value)}
            />
          </div>

          <div className="stocks-grid">
            {filteredStocks.map((stock) => {
              const isPositive = stock.changePercent >= 0;

              return (
                <article className="stock-card" key={stock.id}>
                  <div className="stock-card-header">
                    <div>
                      <h3>{stock.symbol}</h3>
                      <p>{stock.name}</p>
                    </div>
                    <span className={`recommendation-badge ${stock.recommendation.toLowerCase()}`}>{stock.recommendation}</span>
                  </div>

                  <div className="stock-price-row">
                    <strong>${stock.price.toFixed(2)}</strong>
                    <span className={isPositive ? "price-up" : "price-down"}>{isPositive ? "+" : ""}{stock.changePercent.toFixed(2)}%</span>
                  </div>

                  <div className="stock-meta-grid">
                    <p><span>Sector</span>{stock.sector}</p>
                    <p><span>Exchange</span>{stock.exchange}</p>
                    <p><span>Market Cap</span>${stock.marketCapBillion}B</p>
                    <p><span>Volume</span>{stock.volume.toLocaleString()}</p>
                  </div>

                  <p className="stock-rating">AI confidence {stock.rating.score}/5 ({stock.rating.analysts} analysts)</p>

                  <div className="stock-card-actions">
                    <button 
                      className="stock-add-to-cart-btn"
                      onClick={() => addToCart(stock.id, stock.symbol, stock.price, 1)}
                    >
                       Add to cart
                    </button>
                    <button 
                      className="stock-add-to-watchlist-btn"
                      onClick={() => addToWatchlist(stock.id, stock.symbol, stock.price, 1)}
                    >
                      ⭐ Add to watchlist
                    </button>
                  </div>
                </article>
              );
            })}
          </div>

          {filteredStocks.length === 0 && (
            <div className="empty-search-state">
              <p>No stocks matched your search.</p>
              <button type="button" className="clear-search-btn" onClick={() => setSearchText("")}>Clear search</button>
            </div>
          )}
        </section>

        <section className="market-news-ticker" aria-label="Market news ticker">
          <div className="ticker-track">
            {[...newsTickerItems, ...newsTickerItems].map((item, index) => (
              <span key={`${item}-${index}`}>• {item}</span>
            ))}
          </div>
        </section>

        <section className="market-insights-grid">
          <article className="insight-card">
            <h3>Top Gainers</h3>
            {topGainers.map((stock) => (
              <p key={`${stock.id}-g`}><strong>{stock.symbol}</strong><span className="price-up">+{stock.changePercent.toFixed(2)}%</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Top Losers</h3>
            {topLosers.map((stock) => (
              <p key={`${stock.id}-l`}><strong>{stock.symbol}</strong><span className="price-down">{stock.changePercent.toFixed(2)}%</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Most Active</h3>
            {mostActive.map((stock) => (
              <p key={`${stock.id}-a`}><strong>{stock.symbol}</strong><span>{stock.volume.toLocaleString()}</span></p>
            ))}
          </article>

          <article className="insight-card">
            <h3>Sector Overview</h3>
            {sectorOverview.map((sector) => (
              <p key={sector.sector}><strong>{sector.sector}</strong><span className={sector.avgChange >= 0 ? "price-up" : "price-down"}>{sector.avgChange >= 0 ? "+" : ""}{sector.avgChange.toFixed(2)}%</span></p>
            ))}
          </article>
        </section>

        <section className="indices-section">
          <h3>Market Indices Snapshot</h3>
          <div className="indices-grid">
            {indexSnapshot.map((index) => (
              <article className="index-card" key={index.name}>
                <p>{index.name}</p>
                <strong>{index.value}</strong>
                <span className={index.change >= 0 ? "price-up" : "price-down"}>{index.change >= 0 ? "+" : ""}{index.change.toFixed(2)}%</span>
              </article>
            ))}
          </div>
        </section>

        <section className="daily-summary-card">
          <h3>Daily Summary</h3>
          <p>
            Today, the market is <strong>{marketAverage >= 0 ? "up" : "down"} {Math.abs(marketAverage).toFixed(2)}%</strong>. Top performing sector: <strong>{strongestSector?.sector}</strong> ({strongestSector?.avgChange.toFixed(2)}%). Weakest sector: <strong>{weakestSector?.sector}</strong> ({weakestSector?.avgChange.toFixed(2)}%).
          </p>
        </section>

        <section className="news-alerts-grid">
          <article className="news-card">
            <h3>Stock-specific headlines</h3>
            {stockHeadlines.map((headline) => (
              <p key={headline.id}><strong>{headline.title}</strong><span>{headline.source}</span></p>
            ))}
          </article>

          <article className="news-card">
            <h3>Earnings / Dividend Alerts</h3>
            {upcomingAlerts.map((alert) => (
              <p key={`${alert.company}-${alert.when}`}><strong>{alert.label}: {alert.company}</strong><span>{alert.when}</span></p>
            ))}
          </article>
        </section>
        </div>
      </main>
    </>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Header } from "../../components/Header.tsx";
import { stocks } from "../../data/stocks";
import { useCart } from "../../context/CartContext";
import "./WatchlistPage.css";

type WatchlistEntry = {
  stockId: string;
  refPrice: number;
  quantity: number;
};

const DEFAULT_WATCHLIST: WatchlistEntry[] = [
  { stockId: "stk-001-aapl", refPrice: 198.5, quantity: 10 },
  { stockId: "stk-005-nvda", refPrice: 875.0, quantity: 5  },
  { stockId: "stk-007-tsla", refPrice: 245.3, quantity: 8  },
  { stockId: "stk-002-msft", refPrice: 410.0, quantity: 6  },
];

export function WatchlistPage() {
  useEffect(() => { document.title = "Watchlist | TradePulseAI"; }, []);

  const { addToCart } = useCart();
  const [watchlist, setWatchlist] = useState<WatchlistEntry[]>(DEFAULT_WATCHLIST);
  const [search,    setSearch]    = useState("");
  const [addSearch, setAddSearch] = useState("");
  const [addQty,    setAddQty]    = useState(1);
  const [addRef,    setAddRef]    = useState("");
  const [addStock,  setAddStock]  = useState("");
  const [showAdd,   setShowAdd]   = useState(false);

  const watchlistStocks = useMemo(() =>
    watchlist.map((entry) => {
      const stock        = stocks.find((s) => s.id === entry.stockId)!;
      const currentValue = stock.price * entry.quantity;
      const refValue     = entry.refPrice * entry.quantity;
      const pnl          = currentValue - refValue;
      const pnlPct       = ((stock.price - entry.refPrice) / entry.refPrice) * 100;
      return { ...entry, stock, currentValue, refValue, pnl, pnlPct };
    }),
  [watchlist]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return watchlistStocks;
    return watchlistStocks.filter(({ stock }) =>
      [stock.symbol, stock.name, stock.sector].join(" ").toLowerCase().includes(q)
    );
  }, [search, watchlistStocks]);

  const addCandidates = useMemo(() => {
    const inList = new Set(watchlist.map((e) => e.stockId));
    const q = addSearch.trim().toLowerCase();
    return stocks.filter((s) => {
      const notIn = !inList.has(s.id);
      if (!q) return notIn;
      return notIn && [s.symbol, s.name, s.sector].join(" ").toLowerCase().includes(q);
    });
  }, [addSearch, watchlist]);

  const totalRefValue = watchlistStocks.reduce((s, e) => s + e.refValue, 0);
  const totalCurrent  = watchlistStocks.reduce((s, e) => s + e.currentValue, 0);
  const totalPnL      = totalCurrent - totalRefValue;
  const totalPnLPct   = totalRefValue > 0 ? (totalPnL / totalRefValue) * 100 : 0;

  const handleAdd = () => {
    if (!addStock) return;
    const stock    = stocks.find((s) => s.id === addStock)!;
    const refPrice = parseFloat(addRef) || stock.price;
    setWatchlist((prev) => [...prev, { stockId: addStock, refPrice, quantity: addQty }]);
    setAddStock(""); setAddSearch(""); setAddRef(""); setAddQty(1); setShowAdd(false);
  };

  const handleRemove = (stockId: string) =>
    setWatchlist((prev) => prev.filter((e) => e.stockId !== stockId));

  return (
    <>
      <Header />
      <main className="wl-page">

        {/* ── Summary stats ── */}
        <section className="wl-stats">
          <div className="wl-stat-card">
            <span>Monitored Value</span>
            <strong>${totalRefValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className="wl-stat-card">
            <span>Current Value</span>
            <strong>${totalCurrent.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className={`wl-stat-card ${totalPnL >= 0 ? "stat-green" : "stat-red"}`}>
            <span>Total Change ($)</span>
            <strong>{totalPnL >= 0 ? "+" : "−"}${Math.abs(totalPnL).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className={`wl-stat-card ${totalPnLPct >= 0 ? "stat-green" : "stat-red"}`}>
            <span>Total Change (%)</span>
            <strong>{totalPnLPct >= 0 ? "+" : ""}{totalPnLPct.toFixed(2)}%</strong>
          </div>
        </section>

        {/* ── Toolbar ── */}
        <div className="wl-toolbar">
          <div className="wl-search-wrap">
            <input
              type="search"
              className="wl-search"
              placeholder="Search watchlist…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <button className="wl-add-btn" onClick={() => setShowAdd((v) => !v)}>
            {showAdd ? "✕ Cancel" : "+ Add stock"}
          </button>
        </div>

        {/* ── Add stock panel ── */}
        {showAdd && (
          <div className="wl-add-panel">
            <h3>Add a stock to watchlist</h3>
            <div className="wl-add-form">
              <div className="wl-add-search">
                <input
                  type="search"
                  placeholder="Search symbol or company…"
                  value={addSearch}
                  onChange={(e) => setAddSearch(e.target.value)}
                />
                <div className="wl-add-dropdown">
                  {addCandidates.slice(0, 6).map((s) => (
                    <button
                      key={s.id}
                      type="button"
                      className={`wl-add-option ${addStock === s.id ? "selected" : ""}`}
                      onClick={() => { setAddStock(s.id); setAddSearch(s.symbol); }}
                    >
                      <strong>{s.symbol}</strong> — {s.name}
                      <span className={s.changePercent >= 0 ? "price-up" : "price-down"}>
                        ${s.price.toFixed(2)} ({s.changePercent >= 0 ? "+" : ""}{s.changePercent.toFixed(2)}%)
                      </span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="wl-add-fields">
                <label>
                  Ref. price ($)
                  <input
                    type="number"
                    min="0.01"
                    step="0.01"
                    placeholder="e.g. 210.00"
                    value={addRef}
                    onChange={(e) => setAddRef(e.target.value)}
                  />
                </label>
                <label>
                  Quantity
                  <input
                    type="number"
                    min="1"
                    step="1"
                    value={addQty}
                    onChange={(e) => setAddQty(parseInt(e.target.value) || 1)}
                  />
                </label>
                <button
                  type="button"
                  className="wl-confirm-add"
                  disabled={!addStock}
                  onClick={handleAdd}
                >
                  Add to watchlist
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── Watchlist table ── */}
        {filtered.length === 0 ? (
          <div className="wl-empty">
            {watchlist.length === 0
              ? <p>Your watchlist is empty. Add stocks using the button above.</p>
              : <p>No stocks matched your search.</p>}
          </div>
        ) : (
          <div className="wl-table-wrap">
            <table className="wl-table">
              <thead>
                <tr>
                  <th>Symbol</th>
                  <th>Company</th>
                  <th>Signal</th>
                  <th>Current price</th>
                  <th>Day change</th>
                  <th>Ref. price</th>
                  <th>Qty</th>
                  <th>Ref. value</th>
                  <th>Current value</th>
                  <th>Change ($)</th>
                  <th>Change (%)</th>
                  <th></th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(({ stock, refPrice, quantity, refValue, currentValue, pnl, pnlPct }) => (
                  <tr key={stock.id} className={pnl >= 0 ? "row-green" : "row-red"}>
                    <td className={pnl >= 0 ? "symbol-green" : "symbol-red"}>
                      <strong>{stock.symbol}</strong>
                    </td>
                    <td><span className="wl-name">{stock.name}</span><span className="wl-sector">{stock.sector}</span></td>
                    <td><span className={`rec-badge ${stock.recommendation.toLowerCase()}`}>{stock.recommendation}</span></td>
                    <td>${stock.price.toFixed(2)}</td>
                    <td className={stock.changePercent >= 0 ? "price-up" : "price-down"}>
                      {stock.changePercent >= 0 ? "+" : ""}{stock.changePercent.toFixed(2)}%
                    </td>
                    <td>${refPrice.toFixed(2)}</td>
                    <td>{quantity}</td>
                    <td>${refValue.toFixed(2)}</td>
                    <td>${currentValue.toFixed(2)}</td>
                    <td className={pnl >= 0 ? "price-up" : "price-down"}>
                      {pnl >= 0 ? "+" : "−"}${Math.abs(pnl).toFixed(2)}
                    </td>
                    <td className={pnlPct >= 0 ? "price-up" : "price-down"}>
                      {pnlPct >= 0 ? "+" : ""}{pnlPct.toFixed(2)}%
                    </td>
                    <td>
                      <button
                        type="button"
                        className="wl-add-to-cart-btn"
                        onClick={() => addToCart(stock.id, stock.symbol, stock.price, quantity)}
                        title="Add to cart"
                      ></button>
                    </td>
                    <td>
                      <button
                        type="button"
                        className="wl-remove-btn"
                        onClick={() => handleRemove(stock.id)}
                        title="Remove from watchlist"
                      >✕</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Header } from "../../components/Header.tsx";
import { stocks } from "../../data/stocks";
import { useCart } from "../../context/CartContext";
import { useWatchlist, type WatchlistEntry } from "../../context/WatchlistContext";
import "./WatchlistPage.css";

export function WatchlistPage() {
  useEffect(() => { document.title = "Watchlist | TradePulseAI"; }, []);

  const { addToCart } = useCart();
  const { watchlist, addToWatchlist, removeFromWatchlist, updateWatchlistEntry } = useWatchlist();
  const [search, setSearch] = useState("");
  const [addSearch, setAddSearch] = useState("");
  const [addQty, setAddQty] = useState(1);
  const [addRef, setAddRef] = useState("");
  const [addStock, setAddStock] = useState("");
  const [showAdd, setShowAdd] = useState(false);

  const watchlistStocks = useMemo(() =>
    watchlist.map((entry) => {
      const stock        = stocks.find((s) => s.id === entry.stockId)!;
      const currentValue = stock.price * entry.quantity;
      const refValue     = entry.refPrice * entry.quantity;
      const pnl          = currentValue - refValue;
      const pnlPct       = ((stock.price - entry.refPrice) / entry.refPrice) * 100;
      return { ...entry, stock, currentValue, refValue, pnl, pnlPct };
    }),
  [watchlist]);

  const filtered = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return watchlistStocks;
    return watchlistStocks.filter(({ stock }) =>
      [stock.symbol, stock.name, stock.sector].join(" ").toLowerCase().includes(q)
    );
  }, [search, watchlistStocks]);

  const addCandidates = useMemo(() => {
    const inList = new Set(watchlist.map((e) => e.stockId));
    const q = addSearch.trim().toLowerCase();
    return stocks.filter((s) => {
      const notIn = !inList.has(s.id);
      if (!q) return notIn;
      return notIn && [s.symbol, s.name, s.sector].join(" ").toLowerCase().includes(q);
    });
  }, [addSearch, watchlist]);

  const totalRefValue = watchlistStocks.reduce((s, e) => s + e.refValue, 0);
  const totalCurrent  = watchlistStocks.reduce((s, e) => s + e.currentValue, 0);
  const totalPnL      = totalCurrent - totalRefValue;
  const totalPnLPct   = totalRefValue > 0 ? (totalPnL / totalRefValue) * 100 : 0;

  const handleAdd = () => {
    if (!addStock) return;
    const stock    = stocks.find((s) => s.id === addStock)!;
    const refPrice = parseFloat(addRef) || stock.price;
    addToWatchlist(addStock, stock.symbol, refPrice, addQty);
    setAddStock(""); setAddSearch(""); setAddRef(""); setAddQty(1); setShowAdd(false);
  };

  const handleRemove = (stockId: string) =>
    removeFromWatchlist(stockId);

  return (
    <>
      <Header />
      <main className="wl-page">

        {/* ── Summary stats ── */}
        <section className="wl-stats">
          <div className="wl-stat-card">
            <span>Monitored Value</span>
            <strong>${totalRefValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className="wl-stat-card">
            <span>Current Value</span>
            <strong>${totalCurrent.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className={`wl-stat-card ${totalPnL >= 0 ? "stat-green" : "stat-red"}`}>
            <span>Total Change ($)</span>
            <strong>{totalPnL >= 0 ? "+" : "−"}${Math.abs(totalPnL).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</strong>
          </div>
          <div className={`wl-stat-card ${totalPnLPct >= 0 ? "stat-green" : "stat-red"}`}>
            <span>Total Change (%)</span>
            <strong>{totalPnLPct >= 0 ? "+" : ""}{totalPnLPct.toFixed(2)}%</strong>
          </div>
        </section>

        {/* ── Toolbar ── */}
        <div className="wl-toolbar">
          <div className="wl-search-wrap">
            <input
              type="search"
              className="wl-search"
              placeholder="Search watchlist…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <button className="wl-add-btn" onClick={() => setShowAdd((v) => !v)}>
            {showAdd ? "✕ Cancel" : "+ Add stock"}
          </button>
        </div>

        {/* ── Add stock panel ── */}
        {showAdd && (
          <div className="wl-add-panel">
            <h3>Add a stock to watchlist</h3>
            <div className="wl-add-form">
              <div className="wl-add-search">
                <input
                  type="search"
                  placeholder="Search symbol or company…"
                  value={addSearch}
                  onChange={(e) => setAddSearch(e.target.value)}
                />
                <div className="wl-add-dropdown">
                  {addCandidates.slice(0, 6).map((s) => (
                    <button
                      key={s.id}
                      type="button"
                      className={`wl-add-option ${addStock === s.id ? "selected" : ""}`}
                      onClick={() => { setAddStock(s.id); setAddSearch(s.symbol); }}
                    >
                      <strong>{s.symbol}</strong> — {s.name}
                      <span className={s.changePercent >= 0 ? "price-up" : "price-down"}>
                        ${s.price.toFixed(2)} ({s.changePercent >= 0 ? "+" : ""}{s.changePercent.toFixed(2)}%)
                      </span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="wl-add-fields">
                <label>
                  Ref. price ($)
                  <input
                    type="number"
                    min="0.01"
                    step="0.01"
                    placeholder="e.g. 210.00"
                    value={addRef}
                    onChange={(e) => setAddRef(e.target.value)}
                  />
                </label>
                <label>
                  Quantity
                  <input
                    type="number"
                    min="1"
                    step="1"
                    value={addQty}
                    onChange={(e) => setAddQty(parseInt(e.target.value) || 1)}
                  />
                </label>
                <button
                  type="button"
                  className="wl-confirm-add"
                  disabled={!addStock}
                  onClick={handleAdd}
                >
                  Add to watchlist
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── Watchlist table ── */}
        {filtered.length === 0 ? (
          <div className="wl-empty">
            {watchlist.length === 0
              ? <p>Your watchlist is empty. Add stocks using the button above.</p>
              : <p>No stocks matched your search.</p>}
          </div>
        ) : (
          <div className="wl-table-wrap">
            <table className="wl-table">
              <thead>
                <tr>
                  <th>Symbol</th>
                  <th>Company</th>
                  <th>Signal</th>
                  <th>Current price</th>
                  <th>Day change</th>
                  <th>Ref. price</th>
                  <th>Qty</th>
                  <th>Ref. value</th>
                  <th>Current value</th>
                  <th>Change ($)</th>
                  <th>Change (%)</th>
                  <th></th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(({ stock, refPrice, quantity, refValue, currentValue, pnl, pnlPct }) => (
                  <tr key={stock.id} className={pnl >= 0 ? "row-green" : "row-red"}>
                    <td className={pnl >= 0 ? "symbol-green" : "symbol-red"}>
                      <strong>{stock.symbol}</strong>
                    </td>
                    <td><span className="wl-name">{stock.name}</span><span className="wl-sector">{stock.sector}</span></td>
                    <td><span className={`rec-badge ${stock.recommendation.toLowerCase()}`}>{stock.recommendation}</span></td>
                    <td>${stock.price.toFixed(2)}</td>
                    <td className={stock.changePercent >= 0 ? "price-up" : "price-down"}>
                      {stock.changePercent >= 0 ? "+" : ""}{stock.changePercent.toFixed(2)}%
                    </td>
                    <td>${refPrice.toFixed(2)}</td>
                    <td>{quantity}</td>
                    <td>${refValue.toFixed(2)}</td>
                    <td>${currentValue.toFixed(2)}</td>
                    <td className={pnl >= 0 ? "price-up" : "price-down"}>
                      {pnl >= 0 ? "+" : "−"}${Math.abs(pnl).toFixed(2)}
                    </td>
                    <td className={pnlPct >= 0 ? "price-up" : "price-down"}>
                      {pnlPct >= 0 ? "+" : ""}{pnlPct.toFixed(2)}%
                    </td>
                    <td>
                      <button
                        type="button"
                        className="wl-add-to-cart-btn"
                        onClick={() => addToCart(stock.id, stock.symbol, stock.price, quantity)}
                        title="Add to cart"
                      ></button>
                    </td>
                    <td>
                      <button
                        type="button"
                        className="wl-remove-btn"
                        onClick={() => handleRemove(stock.id)}
                        title="Remove from watchlist"
                      >✕</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </>
  );
}
